INSERT INTO `faqs` (`question`, `answer`, `order`) VALUES
('Bagaimana alur seleksi masuk Omah Ngaji?', '<ol><li>Mengisi formulir pendaftaran.</li><li>Melakukan konfirmasi pada nomor yang tercantum.</li><li>Melakukan Interview dan Screening sesuai waktu dan tempat yang telah ditentukan.</li><li>Menunggu pengumuman.</li></ol>', 1),
('Apakah ada aturan bagi mahasiswa yang masuk Omah Ngaji, sebelumnya harus pernah mondok?', 'Tidak, Omah Ngaji Al Anshori terbuka bagi siapa saja yang siap kuliah dan ngaji.', 2),
('Apakah masuk Omah Ngaji harus punya hafalan Al-qur’an?', 'Tidak harus, salah satu Program di Omah Ngaji Al Anshori adalah Ngaji Quran, hal ini memberikan wadah bagi santri untuk belajar dan menghafal Al Quran.', 3),
('Apakah harus bisa baca kitab kuning ?', 'Tidak harus, Ngaji Kitab di Omah Ngaji Al Anshori dengan Metode Bandongan, Guru menyampaikan apa yang ada di dalam kitab dan menjelaskan, santri menulis, mendengarkan, dan memahami.', 4),
('Apakah boleh hanya mengikuti Kegiatan di Omah Ngaji tapi tidurnya di kos?', 'Tentu saja boleh, Omah Ngaji Al Anshori membuka diri bagi siapa saja yang ingin belajar bersama.', 5),
('Apa maksud santri mukim?', 'Santri mukim adalah santri Omah Ngaji yang tidur menginap di Asrama Omah Ngaji Al Anshori.', 6),
('Apa maksud santri non mukim?', 'Santri non mukim adalah santri yang hanya mengikuti kegiatan Omah Ngaji, tetapi tidak tidur menginap di Omah Ngaji Al Anshori.', 7),
('Berapa jarak antara Omah Ngaji ke UNS?', 'Jarak Omah Ngaji Al Anshori dengan UNS sekitar 2,3 KM.', 8),
('Apa yang masuk Omah Ngaji harus dari UNS?', 'Tentu saja tidak, Omah Ngaji Al Anshori terbuka untuk kampus sekitar Omah Ngaji seperti ISI Surakarta, Politeknik Akbara, AK Tekstil Solo, Poltekkes Surakarta, dan sekitarnya.', 9),
('Berapa jumlah santri per kamar?', 'Untuk Putri dihuni 2-4 orang per kamar sesuai dengan ukuran kamar. Untuk Putra dihuni 3-5 orang per kamar sesuai dengan ukuran kamar.', 10),
('Apa di Omah Ngaji sudah disediakan makan?', 'Omah Ngaji Al Anshori menyediakan makan pagi dan sore, setiap santri akan mendapatkan piket masak.', 11),
('Apakah tinggal di Omah Ngaji boleh ikut Organisasi kampus?', 'Omah Ngaji Al Anshori mendukung dan memberikan kebebasan pada setiap santri untuk ikut dan aktif di Organisasi kampus maupun luar kampus.', 12);
